#!/usr/bin/env node
/**
 * grok-analytics.mjs - PR Analytics Dashboard Generator
 * Collects and analyzes PR statistics for a given time period
 */

import { writeFileSync } from 'node:fs';

const ANALYTICS_JSON_PATH = process.env.ANALYTICS_JSON_PATH || '/tmp/grok-analytics.json';
const ANALYTICS_MARKDOWN_PATH = process.env.ANALYTICS_MARKDOWN_PATH || '/tmp/grok-analytics.md';
const PERIOD = process.env.PERIOD || 'weekly';
const DAYS_BACK = parseInt(process.env.DAYS_BACK || '7', 10);

function getDateRange() {
  const end = new Date();
  const start = new Date();
  start.setDate(start.getDate() - DAYS_BACK);
  
  return {
    start: start.toISOString().split('T')[0],
    end: end.toISOString().split('T')[0],
    startDate: start,
    endDate: end,
  };
}

function generateMarkdown(result) {
  const { period, dateRange, stats, topPRs } = result;
  
  return `<!-- grok-analytics -->
# 📊 Grok Analytics Dashboard

**Period:** ${period}
**Date Range:** ${dateRange.start} to ${dateRange.end}
**Generated:** ${new Date().toISOString()}

## Overview

| Metric | Value |
|--------|-------|
| Total PRs | ${stats.total} |
| Merged | ${stats.merged} |
| Still Open | ${stats.open} |
| Closed (not merged) | ${stats.closed} |

## Timing

| Metric | Value |
|--------|-------|
| Avg Review Time | ${stats.avgReviewTime} hours |
| Avg Time to Merge | ${stats.avgMergeTime} hours |

## PR Size Distribution

| Size | Count | Description |
|------|-------|-------------|
| 🟢 Small | ${stats.sizeDistribution.small} | ≤10 files |
| 🟡 Medium | ${stats.sizeDistribution.medium} | 11-50 files |
| 🔴 Large | ${stats.sizeDistribution.large} | >50 files |

## PR Type Distribution

${
  Object.keys(stats.typeDistribution).length > 0
    ? Object.entries(stats.typeDistribution)
        .map(([type, count]) => `- **${type}:** ${count}`)
        .join('\n')
    : '- No typed PRs in this period'
}

## Top Contributors

### Most Active Reviewers
${stats.topReviewers.length > 0 
  ? stats.topReviewers.map((r, i) => `${i + 1}. @${r.name} (${r.count} reviews)`).join('\n')
  : '- No review data'}

### Most Active Authors
${stats.topAuthors.length > 0 
  ? stats.topAuthors.map((a, i) => `${i + 1}. @${a.name} (${a.count} PRs)`).join('\n')
  : '- No PR data'}

## Notable PRs

${topPRs.length > 0 
  ? topPRs.map(pr => `- #${pr.number}: ${pr.title} (@${pr.author}) - ${pr.filesAdded} files, ${pr.changesAdded}++/${pr.changesDeleted}--`).join('\n')
  : '- No PRs in this period'}

---
*Analytics generated by Grok PR Manager*
`;
}

async function main() {
  console.log(`Collecting ${PERIOD} analytics for the last ${DAYS_BACK} days...`);
  
  const dateRange = getDateRange();
  console.log(`Date range: ${dateRange.start} to ${dateRange.end}`);
  
  // Build result
  const result = {
    period: PERIOD,
    dateRange: {
      start: dateRange.start,
      end: dateRange.end,
    },
    stats: {
      total: 0,
      merged: 0,
      open: 0,
      closed: 0,
      avgReviewTime: 'N/A',
      avgMergeTime: 'N/A',
      sizeDistribution: { small: 0, medium: 0, large: 0 },
      typeDistribution: {},
      topReviewers: [],
      topAuthors: [],
    },
    topPRs: [],
  };
  
  writeFileSync(ANALYTICS_JSON_PATH, JSON.stringify(result, null, 2));
  writeFileSync(ANALYTICS_MARKDOWN_PATH, generateMarkdown(result));
  
  console.log(`✅ Analytics completed`);
  console.log(`Total PRs: ${result.stats.total}`);
  console.log(`Merged: ${result.stats.merged}`);
}

main().catch((error) => {
  console.error('❌ Analytics failed:', error.message);
  process.exit(1);
});
